#include <bits/stdc++.h>
using namespace std;
const int INF=1<<30;
int f,v,a[102][102],last[102][102],dp[102][102];
int main(){
    scanf("%d%d",&f,&v);
    for(int i=1;i<=f;i++)
        for(int j=1;j<=v;j++)
            scanf("%d",&a[i][j]);
    for(int i=1;i<=f;i++)
        for(int j=i;j<=v;j++){
            dp[i][j]=a[i][j];
            for(int k=i-1;k<j;k++)
                if(dp[i][j]<dp[i-1][k]+a[i][j] || last[i][j]==0)
                    dp[i][j]=dp[i-1][k]+a[i][j],last[i][j]=k;
        }
    int mx=-INF;
	int p;
    for(int i=f;i<=v;i++)
        if(mx<dp[f][i])
            mx=dp[f][i],p=i;
    stack<int> s;
    for(int i=1;i<=f;i++){
        s.push(p);
        p=last[f-i+1][p];
    }
    printf("%d\n",mx);
    for(int i=1;i<=f;i++){
        printf("%d ",s.top());
        s.pop();
    }
    return 0;
}
